import android.content.Context;import android.content.Intent;import android.net.Uri;import android.os.Build;import android.os.Environment;import android.util.Base64;import android.util.Log;import android.webkit.JavascriptInterface;import java.io.File;import java.io.FileOutputStream;import java.io.IOException;import org.json.JSONObject;public class WebAppInterface {private static final String TAG = "WebAppInterface";private Context mContext;public WebAppInterface(Context c) {mContext = c;}@JavascriptInterfacepublic String saveBase64Image(String base64, String filename) {try {byte[] decodedBytes = Base64.decode(base64, Base64.DEFAULT);File path = Environment.getExternalStoragePublicDirectory(Environment.DIRECTORY_DOWNLOADS);File file = new File(path, filename);FileOutputStream fos = new FileOutputStream(file);fos.write(decodedBytes);fos.close();Log.d(TAG, "Image saved to: " + file.getAbsolutePath());return "{\"status\":\"success\",\"path\":\"" + file.getAbsolutePath() + "\"}";} catch (IOException e) {Log.e(TAG, "Error saving image", e);return "{\"status\":\"error\",\"message\":\"" + e.getMessage() + "\"}";}}@JavascriptInterfacepublic void openExternalApp(String appPackage, String data) {try {Intent intent = mContext.getPackageManager().getLaunchIntentForPackage(appPackage);if (intent != null) {intent.putExtra(Intent.EXTRA_TEXT, data);intent.setAction(Intent.ACTION_SEND);intent.setType("text/plain");mContext.startActivity(intent);} else {Intent browserIntent = new Intent(Intent.ACTION_VIEW, Uri.parse("market://details?id=" + appPackage));mContext.startActivity(browserIntent);}} catch (Exception e) {Log.e(TAG, "Error opening app: " + appPackage, e);}}@JavascriptInterfacepublic String getDeviceInfo() {try {JSONObject info = new JSONObject();info.put("brand", Build.BRAND);info.put("model", Build.MODEL);info.put("sdk", Build.VERSION.SDK_INT);info.put("device", Build.DEVICE);return info.toString();} catch (Exception e) {Log.e(TAG, "Error getting device info", e);return "{}";}}}